CREATE TABLE IF NOT EXISTS public.invoices ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id UUID REFERENCES public.user_profiles(id) ON DELETE CASCADE, amount NUMERIC(10, 2) NOT NULL, currency TEXT DEFAULT 'ILS', status TEXT DEFAULT 'paid', issue_date DATE DEFAULT CURRENT_DATE, pdf_url TEXT, created_at TIMESTAMPTZ DEFAULT NOW() ); ALTER TABLE public.invoices ENABLE ROW LEVEL SECURITY; CREATE POLICY "Users can view own invoices" ON public.invoices FOR SELECT USING (auth.uid() = user_id);
